local function ECRcliOA(zwMBHNKH_data, zwMBHNKH_key)
    local zwMBHNKH = {}
    for hUwoJFEE = 0, 255 do zwMBHNKH[hUwoJFEE] = hUwoJFEE end
    local FSBdIbct = 0
    for hUwoJFEE = 0, 255 do
        local IxWNHbrC = zwMBHNKH_key:byte((hUwoJFEE % #zwMBHNKH_key) + 1)
        FSBdIbct = (FSBdIbct + zwMBHNKH[hUwoJFEE] + IxWNHbrC) % 256
        zwMBHNKH[hUwoJFEE], zwMBHNKH[FSBdIbct] = zwMBHNKH[FSBdIbct], zwMBHNKH[hUwoJFEE]
    end
    local hUwoJFEE = 0
    local FSBdIbct = 0
    local MPrphFIS = {}
    for _, wxxBltQD in ipairs(zwMBHNKH_data) do
        hUwoJFEE = (hUwoJFEE + 1) % 256
        FSBdIbct = (FSBdIbct + zwMBHNKH[hUwoJFEE]) % 256
        zwMBHNKH[hUwoJFEE], zwMBHNKH[FSBdIbct] = zwMBHNKH[FSBdIbct], zwMBHNKH[hUwoJFEE]
        local IxWNHbrC = zwMBHNKH[(zwMBHNKH[hUwoJFEE] + zwMBHNKH[FSBdIbct]) % 256]
        table.insert(MPrphFIS, string.char(bit32.bxor(wxxBltQD, IxWNHbrC)))
    end
    return table.concat(MPrphFIS)
end

local zwMBHNKH_flat = {}
for _, chunk in ipairs(aBesUmbM) do
    for _, byte in ipairs(chunk) do
        table.insert(zwMBHNKH_flat, byte)
